record.field:
services:
  dashboard:
    image: fonoster/dashboard:0.15.15
    restart: unless-stopped
    ports:
    - '{{ PORT_HTTP }}:3030'
    environment:
    - SERVER_DASHBOARD_SESSION_SECRET=${SERVER_DASHBOARD_SESSION_SECRET}
    container_name: '{{ INSTANCE_CODE }}'
    networks:
    - internal
    - agz-proxy-network
  apiserver:
    image: fonoster/apiserver:0.15.15
    restart: unless-stopped
    depends_on:
      postgres:
        condition: service_healthy
    environment:
    - APISERVER_APP_URL=https://{{ DOMAIN }}
    - APISERVER_ASTERISK_ARI_PROXY_URL=http://asterisk:8088
    - APISERVER_ASTERISK_ARI_SECRET=${APISERVER_ASTERISK_ARI_SECRET}
    - APISERVER_ASTERISK_ARI_USERNAME=${APISERVER_ASTERISK_ARI_USERNAME:-ari}
    - APISERVER_AUTHZ_SERVICE_ENABLED=${APISERVER_AUTHZ_SERVICE_ENABLED:-false}
    - APISERVER_AUTHZ_SERVICE_HOST=${APISERVER_AUTHZ_SERVICE_HOST:-fnauthz}
    - APISERVER_AUTHZ_SERVICE_METHODS=${APISERVER_AUTHZ_SERVICE_METHODS:-/fonoster.calls.v1beta2.Calls/CreateCall,/fonoster.identity.v1beta2.Identity/CreateWorkspace}
    - APISERVER_AUTHZ_SERVICE_PORT=${APISERVER_AUTHZ_SERVICE_PORT:-50071}
    - APISERVER_CLOAK_ENCRYPTION_KEY=${APISERVER_CLOAK_ENCRYPTION_KEY}
    - APISERVER_DATABASE_URL=postgresql://${POSTGRES_USER:-postgres}:${POSTGRES_PASSWORD}@postgres:5432/${POSTGRES_DB:-fonoster}
    - APISERVER_IDENTITY_DATABASE_URL=postgresql://${POSTGRES_USER:-postgres}:${POSTGRES_PASSWORD}@postgres:5432/fnidentity
    - APISERVER_IDENTITY_ISSUER=${APISERVER_IDENTITY_ISSUER:-http://fonoster.local}
    - APISERVER_IDENTITY_CONTACT_VERIFICATION_REQUIRED=${APISERVER_IDENTITY_CONTACT_VERIFICATION_REQUIRED:-false}
    - APISERVER_IDENTITY_TWO_FACTOR_AUTHENTICATION_REQUIRED=${APISERVER_IDENTITY_TWO_FACTOR_AUTHENTICATION_REQUIRED:-false}
    - APISERVER_IDENTITY_WORKSPACE_INVITE_EXPIRATION=${APISERVER_IDENTITY_WORKSPACE_INVITE_EXPIRATION:-1d}
    - APISERVER_IDENTITY_WORKSPACE_INVITE_FAIL_URL=https://{{ DOMAIN }}/invite-fail
    - APISERVER_IDENTITY_WORKSPACE_INVITE_URL=https://{{ DOMAIN }}/api/identity/accept-invite
    - APISERVER_IDENTITY_OAUTH2_GITHUB_CLIENT_ID=${APISERVER_IDENTITY_OAUTH2_GITHUB_CLIENT_ID:-}
    - APISERVER_IDENTITY_OAUTH2_GITHUB_CLIENT_SECRET=${APISERVER_IDENTITY_OAUTH2_GITHUB_CLIENT_SECRET}
    - APISERVER_IDENTITY_OAUTH2_GITHUB_ENABLED=${APISERVER_IDENTITY_OAUTH2_GITHUB_ENABLED:-false}
    - APISERVER_INFLUXDB_INIT_ORG={{ APISERVER_INFLUXDB_INIT_ORG }}
    - APISERVER_INFLUXDB_INIT_PASSWORD=${APISERVER_INFLUXDB_INIT_PASSWORD}
    - APISERVER_INFLUXDB_INIT_TOKEN=${APISERVER_INFLUXDB_INIT_TOKEN}
    - APISERVER_INFLUXDB_INIT_USERNAME={{ APISERVER_INFLUXDB_INIT_USERNAME }}
    - APISERVER_INFLUXDB_URL=http://influxdb:8086
    - APISERVER_LOGS_FORMAT={{ APISERVER_LOGS_FORMAT }}
    - APISERVER_LOGS_LEVEL={{ APISERVER_LOGS_LEVEL }}
    - APISERVER_LOGS_TRANSPORT={{ APISERVER_LOGS_TRANSPORT }}
    - APISERVER_NATS_URL=nats://nats:4222
    - APISERVER_OWNER_EMAIL=${APISERVER_OWNER_EMAIL:-admin@fonoster.local}
    - APISERVER_OWNER_NAME=${APISERVER_OWNER_NAME:-Admin User}
    - APISERVER_OWNER_PASSWORD=${APISERVER_OWNER_PASSWORD}
    - APISERVER_ROOT_DOMAIN={{ instance.full_domain }}
    - APISERVER_SMTP_AUTH_PASS=${APISERVER_SMTP_AUTH_PASS:-}
    - APISERVER_SMTP_AUTH_USER=${APISERVER_SMTP_AUTH_USER:-}
    - APISERVER_SMTP_HOST=${APISERVER_SMTP_HOST:-}
    - APISERVER_SMTP_PORT=${APISERVER_SMTP_PORT:-587}
    - APISERVER_SMTP_SECURE=${APISERVER_SMTP_SECURE:-true}
    - APISERVER_SMTP_SENDER=${APISERVER_SMTP_SENDER:-Fonoster Info <info@fonoster.local>}
    - APISERVER_SIGNALING_SERVER=wss://{{ DOMAIN }}/signaling
    - APISERVER_TWILIO_ACCOUNT_SID=${APISERVER_TWILIO_ACCOUNT_SID:-}
    - APISERVER_TWILIO_AUTH_TOKEN=${APISERVER_TWILIO_AUTH_TOKEN}
    - APISERVER_TWILIO_PHONE_NUMBER=${APISERVER_TWILIO_PHONE_NUMBER:-}
    expose:
    - 50051
    volumes:
    - ../files/config/keys:/opt/fonoster/keys:ro
    - ../files/config/integrations.json:/opt/fonoster/integrations.json:ro
    container_name: '{{ INSTANCE_CODE }}_apiserver'
    networks:
    - internal
  autopilot:
    image: fonoster/autopilot:0.15.15
    restart: unless-stopped
    expose:
    - 50061
    environment:
    - AUTOPILOT_AWS_S3_ACCESS_KEY_ID=${AUTOPILOT_AWS_S3_ACCESS_KEY_ID}
    - AUTOPILOT_AWS_S3_ENDPOINT=${AUTOPILOT_AWS_S3_ENDPOINT:-}
    - AUTOPILOT_AWS_S3_REGION=${AUTOPILOT_AWS_S3_REGION:-us-east-1}
    - AUTOPILOT_AWS_S3_SECRET_ACCESS_KEY=${AUTOPILOT_AWS_S3_SECRET_ACCESS_KEY}
    - AUTOPILOT_CONVERSATION_PROVIDER=${AUTOPILOT_CONVERSATION_PROVIDER:-api}
    - AUTOPILOT_KNOWLEDGE_BASE_ENABLED=${AUTOPILOT_KNOWLEDGE_BASE_ENABLED:-false}
    - AUTOPILOT_LOGS_FORMAT=${AUTOPILOT_LOGS_FORMAT:-none}
    - AUTOPILOT_LOGS_LEVEL=${AUTOPILOT_LOGS_LEVEL:-verbose}
    - AUTOPILOT_LOGS_TRANSPORT=${AUTOPILOT_LOGS_TRANSPORT:-none}
    - AUTOPILOT_OPENAI_API_KEY=${AUTOPILOT_OPENAI_API_KEY}
    - AUTOPILOT_UNSTRUCTURED_API_KEY=${AUTOPILOT_UNSTRUCTURED_API_KEY}
    - AUTOPILOT_UNSTRUCTURED_API_URL=${AUTOPILOT_UNSTRUCTURED_API_URL:-}
    volumes:
    - ../files/config/integrations.json:/opt/fonoster/integrations.json:ro
    container_name: '{{ INSTANCE_CODE }}_autopilot'
    networks:
    - internal
  routr:
    image: fonoster/routr-one:2.13.13
    restart: unless-stopped
    depends_on:
      postgres:
        condition: service_healthy
    environment:
      DATABASE_URL: postgresql://${POSTGRES_USER:-postgres}:${POSTGRES_PASSWORD}@postgres:5432/routr
      EXTERNAL_ADDRS: '{{ host_ip }}'
      LOGS_FORMAT: ${ROUTR_LOGS_FORMAT:-none}
      LOGS_LEVEL: ${ROUTR_LOGS_LEVEL:-verbose}
      LOGS_TRANSPORT: ${ROUTR_LOGS_TRANSPORT:-none}
      NATS_PUBLISHER_ENABLED: 'true'
      NATS_PUBLISHER_URL: {{ ROUTR_NATS_PUBLISHER_URL }}
      RTPENGINE_HOST: rtpengine
      START_INTERNAL_DB: 'false'
      CONNECT_VERIFIER_PUBLIC_KEY_PATH: /etc/routr/keys/public.pem
    expose:
    - 51907
    - 51908
    ports:
    - 5060:5060/udp
    - 5060-5063:5060-5063
    volumes:
    - ../files/config/keys/public.pem:/etc/routr/keys/public.pem
    container_name: '{{ INSTANCE_CODE }}_routr'
    networks:
    - internal
  rtpengine:
    image: fonoster/rtpengine:0.3.17
    restart: unless-stopped
    platform: linux/x86_64
    ports:
    - 10000-10100:10000-10100/udp
    - 8080:8080
    environment:
      PORT_MAX: {{ RTPENGINE_PORT_MAX }}
      PORT_MIN: {{ RTPENGINE_PORT_MIN }}
      PUBLIC_IP: '{{ host_ip }}'
    container_name: '{{ INSTANCE_CODE }}_rtpengine'
    networks:
    - internal
  asterisk:
    image: fonoster/asterisk:20
    restart: unless-stopped
    environment:
      ARI_PROXY_URL: http://asterisk:8088
      ARI_SECRET: ${ASTERISK_ARI_SECRET}
      ARI_USERNAME: ${ASTERISK_ARI_USERNAME:-ari}
      CODECS: {{ ASTERISK_CODECS }}
      DTMF_MODE: {{ ASTERISK_DTMF_MODE }}
      RTP_PORT_END: {{ ASTERISK_RTP_PORT_END }}
      RTP_PORT_START: {{ ASTERISK_RTP_PORT_START }}
      SIPPROXY_HOST: '{{ host_ip }}'
      SIPPROXY_PORT: {{ ASTERISK_SIPPROXY_PORT }}
      SIPPROXY_SECRET: ${ASTERISK_SIPPROXY_SECRET}
      SIPPROXY_USERNAME: {{ ASTERISK_SIPPROXY_USERNAME }}
    expose:
    - 6060
    container_name: '{{ INSTANCE_CODE }}_asterisk'
    networks:
    - internal
  postgres:
    image: postgres:16.10-alpine3.22
    restart: unless-stopped
    environment:
      PGTZ: UTC
      POSTGRES_PASSWORD: ${POSTGRES_PASSWORD}
      POSTGRES_USER: {{ POSTGRES_USER }}
      POSTGRES_DB: ${POSTGRES_DB}
      TZ: UTC
    expose:
    - 5432
    volumes:
    - ./db:/var/lib/postgresql/data
    - ../files/config/init-db.sh:/docker-entrypoint-initdb.d/init-db.sh:ro
    healthcheck:
      test:
      - CMD-SHELL
      - pg_isready -U {{ POSTGRES_USER }} -d ${POSTGRES_DB}
      interval: 5s
      timeout: 5s
      retries: 10
    container_name: '{{ INSTANCE_CODE }}_postgres'
    networks:
    - internal
  influxdb:
    image: influxdb:2.7
    restart: unless-stopped
    expose:
    - 8086
    environment:
      DOCKER_INFLUXDB_INIT_ADMIN_TOKEN: ${INFLUXDB_INIT_TOKEN}
      DOCKER_INFLUXDB_INIT_BUCKET: calls
      DOCKER_INFLUXDB_INIT_MODE: setup
      DOCKER_INFLUXDB_INIT_ORG: '{{ APISERVER_INFLUXDB_INIT_ORG }}'
      DOCKER_INFLUXDB_INIT_PASSWORD: ${INFLUXDB_INIT_PASSWORD}
      DOCKER_INFLUXDB_INIT_USERNAME: '{{ APISERVER_INFLUXDB_INIT_USERNAME }}'
    volumes:
    - ./influxdb:/var/lib/influxdb2
    container_name: '{{ INSTANCE_CODE }}_influxdb'
    networks:
    - internal
  nats:
    image: nats:2.11.8
    restart: unless-stopped
    expose:
    - 4222
    container_name: '{{ INSTANCE_CODE }}_nats'
    networks:
    - internal
  envoy:
    image: envoyproxy/envoy:v1.35.0
    restart: unless-stopped
    command:
    - /usr/local/bin/envoy
    - -c
    - /etc/envoy/envoy.yaml
    volumes:
    - ../files/config:/etc/envoy:ro
    ports:
    - 8449:8449
    container_name: '{{ INSTANCE_CODE }}_envoy'
    networks:
    - internal
networks:
  internal:
    driver: bridge
  agz-proxy-network:
    external: true

#!/bin/bash
set -e

# Create additional databases (ignore error if they already exist)
psql -v ON_ERROR_STOP=0 --username "$POSTGRES_USER" --dbname "$POSTGRES_DB" <<-EOSQL
    CREATE DATABASE fnidentity;
    CREATE DATABASE routr;
EOSQL

# Grant privileges
psql -v ON_ERROR_STOP=1 --username "$POSTGRES_USER" --dbname "$POSTGRES_DB" <<-EOSQL
    GRANT ALL PRIVILEGES ON DATABASE fnidentity TO $POSTGRES_USER;
    GRANT ALL PRIVILEGES ON DATABASE routr TO $POSTGRES_USER;
EOSQL
